void badRemoval() {
    // Noncompliant: using remove-erase idiom instead of std::erase
    std::vector<int> vec = {1, 2, 3, 2, 4, 2, 5};

    // Remove all elements with value 2
    vec.erase(std::remove(vec.begin(), vec.end(), 2), vec.end());
}

void badConditionalRemoval() {
    // Noncompliant: using remove_if-erase idiom
    std::vector<int> vec = {1, 2, 3, 4, 5, 6};

    // Remove all even numbers
    vec.erase(std::remove_if(vec.begin(), vec.end(), [](int n) {
        return n % 2 == 0;
    }), vec.end());
}

compliant:
void goodRemoval() {
    // Compliant: using std::erase (C++20)
    std::vector<int> vec = {1, 2, 3, 2, 4, 2, 5};

    // Remove all elements with value 2
    std::erase(vec, 2);
}

void goodConditionalRemoval() {
    // Compliant: using std::erase_if (C++20)
    std::vector<int> vec = {1, 2, 3, 4, 5, 6};

    // Remove all even numbers
    std::erase_if(vec, [](int n) {
        return n % 2 == 0;
    });
}

void goodListRemoval() {
    // Compliant: using std::erase with std::list
    std::list<std::string> lst = {"apple", "banana", "cherry", "banana"};

    // Remove all "banana" elements
    std::erase(lst, "banana");
}
